diffs.replacement:
{
  "name": "Fancy Edge Platform Control",
  "description": "A production-grade dashboard for managing Raspberry Pi 5 clusters, monitoring NVMe-backed inference pipelines, and visualizing Sense HAT telemetry.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface NodeStats {
  id: string;
  name: string;
  role: 'Master' | 'Agent';
  status: 'Online' | 'Offline' | 'Warning';
  cpuUsage: number;
  memoryUsage: number;
  temp: number;
  nvmeStatus: string;
  uptime: string;
  ip: string;
}

export interface InferenceMetric {
  timestamp: string;
  latency: number;
  throughput: number;
}

export interface TelemetryData {
  temp: number;
  humidity: number;
  pressure: number;
  accel: { x: number; y: number; z: number };
}

export enum AppTab {
  DASHBOARD = 'dashboard',
  NODES = 'nodes',
  INFERENCE = 'inference',
  TELEMETRY = 'telemetry',
  LOGS = 'logs',
  AI_INSIGHTS = 'ai_insights'
}

import { GoogleGenAI } from "@google/genai";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const analyzeClusterHealth = async (clusterState: any) => {
  const ai = getAIClient();
  const prompt = `
    Analyze the following Raspberry Pi 5 Edge Cluster state and provide optimization recommendations:
    ${JSON.stringify(clusterState, null, 2)}

    Focus on:
    1. Inference latency optimization.
    2. NVMe thermal management.
    3. k3s load balancing.
    4. Hardware health.

    Keep response concise and technical. Use Markdown.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "Unable to generate insights at this time.";
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Analysis failed. Please check your network or API key configuration.";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Activity, 
  Cpu, 
  Database, 
  HardDrive, 
  LayoutDashboard, 
  List, 
  Zap, 
  Thermometer, 
  ShieldAlert, 
  RefreshCcw,
  Sparkles,
  Terminal,
  Layers,
  BarChart3
} from 'lucide-react';
import { 
  LineChart, 
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  AreaChart, 
  Area 
} from 'recharts';
import { AppTab, NodeStats, InferenceMetric, TelemetryData } from './types';
import { analyzeClusterHealth } from './services/geminiService';

// --- Mock Data Generators ---
const generateMockNodes = (): NodeStats[] => [
  { id: 'pi-01', name: 'Master-Node', role: 'Master', status: 'Online', cpuUsage: 24, memoryUsage: 42, temp: 48, nvmeStatus: 'Healthy', uptime: '12d 4h', ip: '192.168.1.100' },
  { id: 'pi-02', name: 'Agent-AI-01', role: 'Agent', status: 'Online', cpuUsage: 88, memoryUsage: 65, temp: 62, nvmeStatus: 'Active', uptime: '12d 3h', ip: '192.168.1.101' },
  { id: 'pi-03', name: 'Agent-AI-02', role: 'Agent', status: 'Online', cpuUsage: 76, memoryUsage: 58, temp: 59, nvmeStatus: 'Active', uptime: '12d 3h', ip: '192.168.1.102' },
  { id: 'pi-04', name: 'Agent-Sense-01', role: 'Agent', status: 'Online', cpuUsage: 12, memoryUsage: 30, temp: 42, nvmeStatus: 'Standby', uptime: '10d 1h', ip: '192.168.1.103' },
];

const generateMockMetrics = (count: number): InferenceMetric[] => {
  return Array.from({ length: count }).map((_, i) => ({
    timestamp: `${i}:00`,
    latency: 20 + Math.random() * 15,
    throughput: 45 + Math.random() * 20
  }));
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [nodes, setNodes] = useState<NodeStats[]>(generateMockNodes());
  const [metrics, setMetrics] = useState<InferenceMetric[]>(generateMockMetrics(24));
  const [telemetry, setTelemetry] = useState<TelemetryData>({
    temp: 24.5,
    humidity: 48.2,
    pressure: 1013.1,
    accel: { x: 0.01, y: -0.02, z: 0.98 }
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const addLog = useCallback((msg: string) => {
    setLogs(prev => [
      `[${new Date().toLocaleTimeString()}] ${msg}`,
      ...prev.slice(0, 49)
    ]);
  }, []);

  // Simulate real-time updates
  useEffect(() => {
    const interval = setInterval(() => {
      setNodes(prev => prev.map(n => ({
        ...n,
        cpuUsage: Math.min(100, Math.max(0, n.cpuUsage + (Math.random() - 0.5) * 10)),
        temp: Math.min(85, Math.max(30, n.temp + (Math.random() - 0.5) * 2))
      })));

      setMetrics(prev => {
        const next = [...prev.slice(1), {
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
          latency: 20 + Math.random() * 15,
          throughput: 45 + Math.random() * 20
        }];
        return next;
      });

      setTelemetry(prev => ({
        ...prev,
        temp: prev.temp + (Math.random() - 0.5) * 0.1,
        humidity: prev.humidity + (Math.random() - 0.5) * 0.5,
        pressure: prev.pressure + (Math.random() - 0.5) * 0.2
      }));
    }, 3000);

    addLog("Fancy Edge Platform Initialized");
    addLog("k3s Cluster Check: All nodes ready");
    addLog("NVMe mounting confirmed on all workers");

    return () => clearInterval(interval);
  }, [addLog]);

  const handleRunAnalysis = async () => {
    setIsAnalyzing(true);
    addLog("Initiating AI Cluster Analysis...");
    const result = await analyzeClusterHealth({ nodes, metrics, telemetry });
    setAiInsights(result);
    setIsAnalyzing(false);
    addLog("AI Analysis complete.");
  };

  const renderSidebarItem = (id: AppTab, label: string, icon: React.ReactNode) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex items-center gap-3 px-4 py-3 w-full transition-all duration-200 border-r-4 ${
        activeTab === id 
          ? 'bg-blue-600/20 text-blue-400 border-blue-500 font-medium' 
          : 'text-slate-400 border-transparent hover:bg-slate-800 hover:text-slate-200'
      }`}
    >
      {icon}
      <span className="text-sm">{label}</span>
    </button>
  );

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col shrink-0">
        <div className="p-6 border-b border-slate-800 flex items-center gap-3">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-900/20">
            <Zap size={20} className="text-white fill-current" />
          </div>
          <h1 className="font-bold text-lg tracking-tight bg-gradient-to-r from-blue-400 to-emerald-400 bg-clip-text text-transparent">
            Fancy Edge
          </h1>
        </div>

        <nav className="flex-1 mt-4">
          {renderSidebarItem(AppTab.DASHBOARD, 'Overview', <LayoutDashboard size={18} />)}
          {renderSidebarItem(AppTab.NODES, 'Cluster Nodes', <Cpu size={18} />)}
          {renderSidebarItem(AppTab.INFERENCE, 'Inference Pipeline', <Activity size={18} />)}
          {renderSidebarItem(AppTab.TELEMETRY, 'Sense Telemetry', <Database size={18} />)}
          {renderSidebarItem(AppTab.LOGS, 'System Logs', <Terminal size={18} />)}
          <div className="mt-8 px-4 py-2 text-xs font-semibold text-slate-500 uppercase tracking-widest">Advanced</div>
          {renderSidebarItem(AppTab.AI_INSIGHTS, 'AI Insights', <Sparkles size={18} />)}
        </nav>

        <div className="p-4 bg-slate-900/50 border-t border-slate-800">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <span className="text-xs text-slate-400">Cluster Status: Healthy</span>
          </div>
          <div className="text-[10px] text-slate-500 font-mono">
            Uptime: 12d 04:32:11
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto bg-slate-950 p-8">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-white capitalize">{activeTab.replace('_', ' ')}</h2>
            <p className="text-slate-400 text-sm">Real-time control plane for Pi-5 edge infrastructure.</p>
          </div>
          <div className="flex gap-4">
            <button className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg border border-slate-700 transition-colors text-sm font-medium">
              <RefreshCcw size={16} /> Sync Cluster
            </button>
            <button className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg shadow-lg shadow-blue-900/20 transition-all text-sm font-medium">
              <Layers size={16} /> Deploy Manifest
            </button>
          </div>
        </header>

        {/* Tab Content */}
        {activeTab === AppTab.DASHBOARD && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              <StatCard title="Total Nodes" value="4" icon={<Cpu className="text-blue-400" />} subtitle="k3s Multi-node" />
              <StatCard title="Avg Latency" value="24.2ms" icon={<Activity className="text-emerald-400" />} subtitle="Inference P95" />
              <StatCard title="Memory Used" value="12.4GB" icon={<Database className="text-amber-400" />} subtitle="Across cluster" />
              <StatCard title="Storage" value="2.4TB" icon={<HardDrive className="text-purple-400" />} subtitle="NVMe RAID-0" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <Card title="Inference Performance (Latency vs Throughput)">
                <div className="h-64 mt-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={metrics}>
                      <defs>
                        <linearGradient id="colorLat" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                          <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                      <XAxis dataKey="timestamp" stroke="#64748b" fontSize={10} tick={{fill: '#64748b'}} />
                      <YAxis stroke="#64748b" fontSize={10} tick={{fill: '#64748b'}} />
                      <Tooltip 
                        contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '8px' }}
                        itemStyle={{ color: '#94a3b8' }}
                      />
                      <Area type="monotone" dataKey="latency" stroke="#3b82f6" fillOpacity={1} fill="url(#colorLat)" strokeWidth={2} />
                      <Line type="monotone" dataKey="throughput" stroke="#10b981" strokeWidth={2} dot={false} />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </Card>

              <Card title="Live Node Health Matrix">
                <div className="space-y-4 mt-2">
                  {nodes.map(node => (
                    <div key={node.id} className="flex items-center justify-between p-3 bg-slate-900/50 rounded-lg border border-slate-800">
                      <div className="flex items-center gap-3">
                        <div className={`w-2 h-2 rounded-full ${node.status === 'Online' ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                        <div>
                          <div className="text-sm font-semibold">{node.name}</div>
                          <div className="text-[10px] text-slate-500">{node.ip} • {node.role}</div>
                        </div>
                      </div>
                      <div className="flex gap-6">
                        <div className="text-right">
                          <div className="text-[10px] text-slate-500 uppercase">CPU</div>
                          <div className="text-xs font-mono">{node.cpuUsage.toFixed(1)}%</div>
                        </div>
                        <div className="text-right">
                          <div className="text-[10px] text-slate-500 uppercase">Temp</div>
                          <div className={`text-xs font-mono ${node.temp > 60 ? 'text-amber-500' : 'text-slate-300'}`}>
                            {node.temp.toFixed(1)}°C
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>
            </div>
          </div>
        )}

        {activeTab === AppTab.NODES && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-6">
            {nodes.map(node => (
              <NodeCard key={node.id} node={node} />
            ))}
          </div>
        )}

        {activeTab === AppTab.TELEMETRY && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <TelemetryCard title="Ambient Temp" value={`${telemetry.temp.toFixed(2)}°C`} icon={<Thermometer className="text-orange-400" />} />
              <TelemetryCard title="Humidity" value={`${telemetry.humidity.toFixed(1)}%`} icon={<Activity className="text-blue-400" />} />
              <TelemetryCard title="Barometric" value={`${telemetry.pressure.toFixed(1)} hPa`} icon={<BarChart3 className="text-emerald-400" />} />
            </div>
            <Card title="Orientation (Accelerometer)">
              <div className="grid grid-cols-3 gap-8 p-4">
                <div className="text-center">
                  <div className="text-slate-500 text-xs mb-1">X-Axis</div>
                  <div className="text-2xl font-mono text-white">{telemetry.accel.x.toFixed(4)}</div>
                </div>
                <div className="text-center">
                  <div className="text-slate-500 text-xs mb-1">Y-Axis</div>
                  <div className="text-2xl font-mono text-white">{telemetry.accel.y.toFixed(4)}</div>
                </div>
                <div className="text-center">
                  <div className="text-slate-500 text-xs mb-1">Z-Axis</div>
                  <div className="text-2xl font-mono text-white">{telemetry.accel.z.toFixed(4)}</div>
                </div>
              </div>
            </Card>
          </div>
        )}

        {activeTab === AppTab.LOGS && (
          <Card title="System Stream">
            <div className="bg-black/40 rounded-lg p-4 font-mono text-xs h-[500px] overflow-y-auto space-y-1">
              {logs.length > 0 ? (
                logs.map((log, i) => (
                  <div key={i} className="flex gap-2">
                    <span className="text-slate-600">[{i}]</span>
                    <span className={log.includes('Error') ? 'text-red-400' : log.includes('AI') ? 'text-blue-400' : 'text-slate-300'}>
                      {log}
                    </span>
                  </div>
                ))
              ) : (
                <div className="text-slate-600 animate-pulse">Waiting for events...</div>
              )}
            </div>
          </Card>
        )}

        {activeTab === AppTab.AI_INSIGHTS && (
          <div className="space-y-6">
            <div className="bg-slate-900 border border-blue-500/30 rounded-xl p-8 text-center">
              <div className="w-16 h-16 bg-blue-600/20 text-blue-400 rounded-full flex items-center justify-center mx-auto mb-4">
                <Sparkles size={32} />
              </div>
              <h3 className="text-xl font-bold mb-2">Gemini Pro Reasoning</h3>
              <p className="text-slate-400 max-w-lg mx-auto mb-6">
                Use advanced AI to evaluate your cluster's performance logs, resource allocation, and inference efficiency.
              </p>
              <button 
                onClick={handleRunAnalysis}
                disabled={isAnalyzing}
                className={`px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg font-bold flex items-center gap-2 mx-auto transition-all ${isAnalyzing ? 'opacity-50 cursor-not-allowed' : 'hover:scale-105 active:scale-95'}`}
              >
                {isAnalyzing ? (
                  <>
                    <RefreshCcw className="animate-spin" size={18} />
                    Analyzing Infrastructure...
                  </>
                ) : (
                  <>
                    <Activity size={18} />
                    Analyze Cluster Health
                  </>
                )}
              </button>
            </div>

            {aiInsights && (
              <Card title="Optimization Report">
                <div className="prose prose-invert max-w-none text-slate-300 font-mono text-sm leading-relaxed p-2 whitespace-pre-wrap">
                  {aiInsights}
                </div>
              </Card>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

// --- Helper Components ---

const Card: React.FC<{ title: string; children: React.ReactNode }> = ({ title, children }) => (
  <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-sm overflow-hidden">
    <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
      <List size={14} className="text-blue-500" />
      {title}
    </h3>
    {children}
  </div>
);

const StatCard: React.FC<{ title: string; value: string; icon: React.ReactNode; subtitle: string }> = ({ title, value, icon, subtitle }) => (
  <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-sm">
    <div className="flex items-center justify-between mb-2">
      <span className="text-slate-400 text-xs font-semibold uppercase tracking-wider">{title}</span>
      <div className="p-2 bg-slate-800 rounded-lg">{icon}</div>
    </div>
    <div className="text-2xl font-bold text-white mb-1">{value}</div>
    <div className="text-xs text-slate-500">{subtitle}</div>
  </div>
);

const TelemetryCard: React.FC<{ title: string; value: string; icon: React.ReactNode }> = ({ title, value, icon }) => (
  <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-sm flex items-center gap-4">
    <div className="w-12 h-12 bg-slate-800 rounded-xl flex items-center justify-center text-2xl">
      {icon}
    </div>
    <div>
      <div className="text-slate-500 text-xs font-semibold uppercase tracking-wider">{title}</div>
      <div className="text-2xl font-bold text-white font-mono">{value}</div>
    </div>
  </div>
);

const NodeCard: React.FC<{ node: NodeStats }> = ({ node }) => (
  <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-sm hover:border-slate-700 transition-colors">
    <div className="flex justify-between items-start mb-6">
      <div className="flex items-center gap-4">
        <div className={`p-3 rounded-xl ${node.role === 'Master' ? 'bg-indigo-600/20 text-indigo-400' : 'bg-slate-800 text-slate-400'}`}>
          <Cpu size={24} />
        </div>
        <div>
          <h4 className="font-bold text-white">{node.name}</h4>
          <span className="text-xs text-slate-500 font-mono">{node.ip}</span>
        </div>
      </div>
      <div className="flex flex-col items-end">
        <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${node.status === 'Online' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-red-500/10 text-red-500'}`}>
          {node.status}
        </span>
        <span className="text-[10px] text-slate-500 mt-1 uppercase tracking-tighter">ROLE: {node.role}</span>
      </div>
    </div>

    <div className="grid grid-cols-2 gap-6 mb-6">
      <div className="space-y-2">
        <div className="flex justify-between text-[10px] text-slate-500 uppercase font-semibold">
          <span>CPU LOAD</span>
          <span>{node.cpuUsage.toFixed(1)}%</span>
        </div>
        <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
          <div className={`h-full transition-all duration-1000 ${node.cpuUsage > 80 ? 'bg-red-500' : 'bg-blue-500'}`} style={{ width: `${node.cpuUsage}%` }}></div>
        </div>
      </div>
      <div className="space-y-2">
        <div className="flex justify-between text-[10px] text-slate-500 uppercase font-semibold">
          <span>MEM USAGE</span>
          <span>{node.memoryUsage}%</span>
        </div>
        <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
          <div className="h-full bg-emerald-500 transition-all duration-1000" style={{ width: `${node.memoryUsage}%` }}></div>
        </div>
      </div>
    </div>

    <div className="flex items-center justify-between pt-4 border-t border-slate-800 text-xs">
      <div className="flex items-center gap-2 text-slate-400">
        <Thermometer size={14} className={node.temp > 60 ? 'text-amber-500' : 'text-blue-500'} />
        <span>{node.temp.toFixed(1)}°C</span>
      </div>
      <div className="flex items-center gap-2 text-slate-400">
        <HardDrive size={14} className="text-slate-500" />
        <span className="text-[10px]">{node.nvmeStatus}</span>
      </div>
      <div className="text-slate-500 font-mono text-[10px]">
        {node.uptime}
      </div>
    </div>
  </div>
);

export default App;

export interface NodeStats {
  id: string;
  name: string;
  role: 'Master' | 'Agent';
  status: 'Online' | 'Offline' | 'Warning';
  cpuUsage: number;
  memoryUsage: number;
  temp: number;
  nvmeStatus: string;
  uptime: string;
  ip: string;
  meshIp: string;
  encrypted: boolean;
}

export interface InferenceMetric {
  timestamp: string;
  latency: number;
  throughput: number;
}

export interface LocalModel {
  id: string;
  name: string;
  version: string;
  size: string;
  hash: string;
  status: 'Verified' | 'Syncing' | 'Corrupt';
}

export interface FederatedRound {
  round: number;
  accuracy: number;
  loss: number;
  clients: number;
  timestamp: string;
}

export interface P2PPeer {
  id: string;
  type: 'Syncthing' | 'IPFS';
  address: string;
  traffic: string;
  latency: string;
}

export interface TelemetryData {
  temp: number;
  humidity: number;
  pressure: number;
  accel: { x: number; y: number; z: number };
}

export enum AppTab {
  DASHBOARD = 'dashboard',
  NODES = 'nodes',
  INFERENCE = 'inference',
  FEDERATED = 'federated_learning',
  MARKETPLACE = 'marketplace',
  P2P = 'p2p_sync',
  TELEMETRY = 'telemetry',
  LOGS = 'logs',
  AI_INSIGHTS = 'ai_insights'
}

import { GoogleGenAI } from "@google/genai";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const analyzeClusterHealth = async (clusterState: any) => {
  const ai = getAIClient();
  const prompt = `
    Perform a SOVEREIGN ANALYSIS of the following Raspberry Pi 5 Edge Cluster:
    ${JSON.stringify(clusterState, null, 2)}

    The user is running an offline-first, zero-cloud platform. Provide technical optimization recommendations focusing on:
    1. Federated Learning efficiency and client contribution balance.
    2. NVMe thermal throttling vs. Model Marketplace sync speeds.
    3. P2P Mesh network (WireGuard) stability.
    4. Hardware health (CPU/Temp) and energy consumption.

    Ensure suggestions are purely local (no cloud APIs). Keep response technical and use Markdown.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "Unable to generate sovereign insights at this time.";
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Analysis failed. Ensure your platform has external gateway access for this specific request or check API configuration.";
  }
};

